public void testOrderProcessing() {
    Order mockOrder = mock(Order.class);

    // These 4 when() calls on the same mock exceed the default limit of 3
    when(mockOrder.getTotal()).thenReturn(100.0);
    when(mockOrder.getStatus()).thenReturn("PENDING");
    when(mockOrder.getItems()).thenReturn(items);
    when(mockOrder.getId()).thenReturn("123");

    // Process the order...
}


// Violation: getter with parameter (when allowedParameters=0)
public String getDrAccType(String flexResStr) {
return flexResStr.substring(0, 5);
}

// Violation: getter with multiple statements (when allowedStatements=1)
public String getDrAccType() {
String flexRes = getFlexRes();
String drAccType = flexRes.substring(0, 5);
return drAccType;
}

// Violation: static getter (when checkNotStatic=true)
public static String getName() {
return "default";
}

// Violation: final getter (when checkNotFinal=true)
public final String getName() {
return name;
}

// Violation: non-public getter (when checkPublic=true)
private String getName() {
return name;
}

// Good: simple getter
public String getName() {
return name;
}

// Good: renamed method that does complex work
public String determineDrAccType(String flexResStr) {
    String flexRes = process(flexResStr);
    return flexRes.substring(0, 5);
}

// Ignored: not a proper getter pattern
public String get() {
    return process();
}

// Ignored: not a proper getter pattern
public boolean gettable(String param) {
    return param != null;
}

// Ignored: not a proper getter pattern
public Supplier<String> getter() {
    return () -> "value";
}
